float sepsis_predict_margin(const float x[SEPSIS_N_FEATURES]) {
    float sum = SEPSIS_BASE_MARGIN;
    for (int t = 0; t < SEPSIS_N_TREES; ++t) {
        unsigned int n = SEPSIS_TREE_ROOTS[t];
        while (SEPSIS_NODES[n].feature != 255) {
            const sepsis_node_t *nd = &SEPSIS_NODES[n];
            float v = x[nd->feature];
            if (isnan(v))      n = nd->missing;
            else if (v < nd->thresh) n = nd->yes;
            else               n = nd->no;
        }
        sum += SEPSIS_NODES[n].leaf;
    }
    return sum;
}

float sepsis_predict_proba(const float x[SEPSIS_N_FEATURES]) {
    return 1.0f / (1.0f + expf(-sepsis_predict_margin(x)));
}
